/* BTDropdown — molecule wrapper
 *
 * Positions BTDropdownList below the trigger using CSS absolute positioning.
 * The wrapper is inline-block so it shrink-wraps to the trigger width.
 *
 * All var() names verified against packages/tokens/platforms/web/bspace/dist/styles.css.
 * No hex fallback per CLAUDE.md §6.
 */

.bt-dropdown {
  position: relative;
  display: inline-block;
}

/* Floating list — absolute, drops below trigger with 4px gap */
.bt-dropdown__list {
  position: absolute;
  top: calc(100% + 4px);
  bottom: auto;
  z-index: 100;
}

/* Horizontal alignment relative to the trigger (logical — auto-flips in RTL) */
.bt-dropdown__list--align-start {
  inset-inline-start: 0;
}

.bt-dropdown__list--align-center {
  left: 50%;
  transform: translateX(-50%);
}

.bt-dropdown__list--align-end {
  inset-inline-end: 0;
}

/* Auto-flip: panel opens above when there is not enough space below */
.bt-dropdown__list--above {
  top: auto;
  bottom: calc(100% + 4px);
}

/**
 * BTDropdown — composable dropdown molecule (React).
 *
 * Handles overlay positioning internally via CSS absolute positioning.
 * Provides a default trigger button or a custom `trigger` render prop.
 *
 * @example
 * // Simple list
 * const [selected, setSelected] = useState<string>();
 * <BTDropdown
 *   items={options}
 *   label="Status"
 *   value={selected}
 *   onSelect={setSelected}
 * />
 *
 * @example
 * // Checkbox multi-select
 * const [values, setValues] = useState<string[]>([]);
 * <BTDropdown
 *   variant="checkbox"
 *   items={options}
 *   label="Assignees"
 *   values={values}
 *   onMultiSelect={setValues}
 * />
 *
 * @example
 * // Custom trigger
 * <BTDropdown
 *   items={options}
 *   trigger={(toggle, isOpen) => (
 *     <button onClick={toggle}>{isOpen ? 'Close' : 'Open'}</button>
 *   )}
 * />
 */
import './BTDropdown.css';
import { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import type { BTDropdownProps } from './BTDropdown.types';
import type { BTDropdownItem } from '../dropdown-list/BTDropdownList.types';
import { BTDropdownList } from '../dropdown-list/BTDropdownList';
import { BTButton } from '../button/BTButton';

export function BTDropdown<T = string>({
  items,
  label = 'Select',
  trigger,
  variant = 'list',
  align = 'start',
  value,
  values,
  searchable = false,
  emptyLabel = 'No result found.',
  onSelect,
  onMultiSelect,
  onOpen,
  onClose,
  className,
}: BTDropdownProps<T>) {
  const [isOpen, setIsOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [openAbove, setOpenAbove] = useState(false);
  const rootRef = useRef<HTMLDivElement>(null);
  const listRef  = useRef<HTMLDivElement>(null);

  // ── Open / close ──────────────────────────────────────────────────────────

  function open() {
    setIsOpen(true);
    setSearchQuery('');
    onOpen?.();
  }

  function close() {
    setIsOpen(false);
    onClose?.();
  }

  function toggle() {
    isOpen ? close() : open();
  }

  // ── Auto-flip: position above when not enough space below ────────────────

  const updateFlip = useCallback(() => {
    const root = rootRef.current;
    const list = listRef.current;
    if (!root || !list) return;
    const triggerRect = root.getBoundingClientRect();
    const listHeight  = list.getBoundingClientRect().height;
    const spaceBelow  = window.innerHeight - triggerRect.bottom - 4;
    const spaceAbove  = triggerRect.top - 4;
    setOpenAbove(spaceBelow < listHeight && spaceAbove >= listHeight);
  }, []);

  useEffect(() => {
    if (!isOpen) return;
    // rAF ensures list is painted before measuring its height
    const raf = requestAnimationFrame(updateFlip);
    window.addEventListener('resize', updateFlip);
    window.addEventListener('scroll', updateFlip, true);
    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener('resize', updateFlip);
      window.removeEventListener('scroll', updateFlip, true);
    };
  }, [isOpen, updateFlip]);

  // ── Click-outside ─────────────────────────────────────────────────────────

  useEffect(() => {
    function handleDocumentClick(event: MouseEvent) {
      if (!isOpen) return;
      if (rootRef.current && !rootRef.current.contains(event.target as Node)) {
        close();
      }
    }
    document.addEventListener('click', handleDocumentClick, true);
    return () => document.removeEventListener('click', handleDocumentClick, true);
  }, [isOpen]); // eslint-disable-line react-hooks/exhaustive-deps

  // ── Selection ─────────────────────────────────────────────────────────────

  function handleSelect(selectedValue: T) {
    onSelect?.(selectedValue);

    if (variant === 'checkbox') {
      const current = values ? [...values] : [];
      const idx = current.indexOf(selectedValue);
      if (idx === -1) {
        current.push(selectedValue);
      } else {
        current.splice(idx, 1);
      }
      onMultiSelect?.(current);
      // Checkbox stays open.
    } else {
      close();
    }
  }

  // ── Resolved items with checked state ─────────────────────────────────────

  const resolvedItems = useMemo<BTDropdownItem<T>[]>(
    () =>
      items.map((item) => {
        const isChecked =
          variant === 'checkbox'
            ? (item.value !== undefined && (values?.includes(item.value) ?? item.checked ?? false))
            : variant === 'radio'
              ? value === item.value
              : (item.checked ?? false);
        return { ...item, checked: isChecked };
      }),
    [items, variant, value, values],
  );

  const filteredItems = useMemo<BTDropdownItem<T>[]>(() => {
    if (!searchable || !searchQuery) return resolvedItems;
    const q = searchQuery.toLowerCase();
    return resolvedItems.filter((i) => (i.label ?? '').toLowerCase().includes(q));
  }, [resolvedItems, searchable, searchQuery]);

  // ── Render ────────────────────────────────────────────────────────────────

  return (
    <div
      ref={rootRef}
      className={['bt-dropdown', className].filter(Boolean).join(' ')}
    >
      {/* Trigger */}
      {trigger
        ? trigger(toggle, isOpen)
        : (
          <BTButton
            variant="secondary-white"
            label={label}
            onClick={toggle}
          />
        )}

      {/* Floating list */}
      {isOpen && (
        <div
          ref={listRef}
          className={[
            'bt-dropdown__list',
            `bt-dropdown__list--align-${align}`,
            openAbove ? 'bt-dropdown__list--above' : '',
          ].filter(Boolean).join(' ')}
        >
          <BTDropdownList<T>
            variant={variant}
            items={filteredItems}
            searchable={searchable}
            searchQuery={searchQuery}
            emptyLabel={emptyLabel}
            onSelect={handleSelect}
            onSearchChange={setSearchQuery}
          />
        </div>
      )}
    </div>
  );
}

BTDropdown.displayName = 'BTDropdown';

/**
 * BTDropdown — composable dropdown molecule types (React).
 * Mirror of Vue BTDropdown.types.ts — keep in sync.
 */
import type { BTDropdownItem, BTDropdownListVariant } from '../dropdown-list/BTDropdownList.types';

/** Horizontal alignment of the floating list relative to its trigger. */
export type BTDropdownAlign = 'start' | 'center' | 'end';

export interface BTDropdownProps<T = string> {
  /** Items to display in the dropdown list. */
  items: BTDropdownItem<T>[];
  /**
   * Label shown on the default trigger button.
   * @default 'Select'
   */
  label?: string;
  /** Optional custom trigger element. Receives toggle + isOpen. */
  trigger?: (toggle: () => void, isOpen: boolean) => React.ReactNode;
  /**
   * Visual layout of the dropdown list.
   * @default 'list'
   */
  variant?: BTDropdownListVariant;
  /** Controlled value for single-select variants. */
  value?: T;
  /** Controlled values for the checkbox multi-select variant. */
  values?: T[];
  /**
   * Horizontal alignment of the floating list relative to the trigger.
   * - `start`: list start edge aligns with the trigger start edge (left in LTR).
   * - `center`: list is centered on the trigger.
   * - `end`: list end edge aligns with the trigger end edge (right in LTR).
   * @default 'start'
   */
  align?: BTDropdownAlign;
  /** Show a search input at the top. @default false */
  searchable?: boolean;
  /** Text shown in the empty state. @default 'No result found.' */
  emptyLabel?: string;
  /** Called when an item is selected (all variants). */
  onSelect?: (value: T) => void;
  /** Called with the updated list after a checkbox toggle. */
  onMultiSelect?: (values: T[]) => void;
  /** Called when the dropdown opens. */
  onOpen?: () => void;
  /** Called when the dropdown closes. */
  onClose?: () => void;
  className?: string;
}
